/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Message formatting: concise text from NotificationPayload
 * - Recipient resolution: resolves user IDs to phone numbers via injected resolver
 * - In-memory send capture for testing (swap transport for production)
 *
 * Implements the NotificationAdapter interface. Must not throw from send().
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * Structure of an SMS message ready for delivery.
 */
export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

/**
 * Function that resolves a recipient identifier to a phone number.
 * Returns null if the recipient cannot be resolved.
 */
export type PhoneNumberResolver = (recipient: string) => Promise<string | null>;

/**
 * Transport function that handles actual SMS delivery.
 * The default stores in-memory; inject a real transport for production.
 */
export type SmsTransport = (message: SmsMessage) => Promise<void>;

/**
 * Format a notification payload into a concise SMS body.
 * SMS messages should be short — subject + truncated body.
 */
function formatSmsBody(payload: NotificationPayload): string {
  const maxLength = 160;
  const text = `${payload.subject}: ${payload.body}`;
  if (text.length <= maxLength) {
    return text;
  }
  return text.slice(0, maxLength - 3) + '...';
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private recipientResolver: PhoneNumberResolver | null;
  private transport: SmsTransport;

  constructor(options?: {
    recipientResolver?: PhoneNumberResolver;
    transport?: SmsTransport;
  }) {
    this.recipientResolver = options?.recipientResolver ?? null;
    this.transport = options?.transport ?? ((msg) => {
      this.sentMessages.push(msg);
      return Promise.resolve();
    });
  }

  /**
   * Send a notification as an SMS.
   *
   * 1. Resolves recipient to a phone number (if resolver is configured)
   * 2. Formats the message body (concise, max 160 chars)
   * 3. Delivers via the configured transport
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      // Step 1: Resolve recipient to phone number
      const phoneNumber = await this.resolveRecipient(payload.recipient);
      if (!phoneNumber) {
        const error = `Could not resolve recipient to phone number: ${payload.recipient}`;
        this.logger.error(error);
        return { success: false, error };
      }

      // Step 2: Format SMS body
      const body = formatSmsBody(payload);

      // Step 3: Deliver via transport
      const message: SmsMessage = {
        to: phoneNumber,
        body,
        sentAt: new Date(),
      };

      await this.transport(message);
      this.logger.info(`SMS sent to ${phoneNumber}: ${payload.id}`);

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Resolve a recipient identifier to a phone number.
   * If the recipient looks like a phone number, return it directly.
   * Otherwise, use the injected resolver.
   */
  private async resolveRecipient(recipient: string): Promise<string | null> {
    if (this.isPhoneNumber(recipient)) {
      return recipient;
    }

    if (this.recipientResolver) {
      return this.recipientResolver(recipient);
    }

    // No resolver and not a phone number — can't deliver
    return null;
  }

  /**
   * Basic check if a string looks like a phone number.
   * Accepts formats like +1234567890, 1234567890, (123) 456-7890.
   */
  private isPhoneNumber(value: string): boolean {
    return /^\+?[\d\s()-]{7,}$/.test(value);
  }

  /**
   * Get all sent messages. Useful for testing.
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

export { formatSmsBody };

