      const result = await adapter.send(makePayload({ recipient: 'user-1' }));

      expect(result.success).toBe(true);
      expect(resolver).toHaveBeenCalledWith('user-1');
      expect(adapter.getSentMessages()[0]?.to).toBe('+15559876543');
    });

    it('should fail when recipient cannot be resolved', async () => {
      adapter = new SmsNotificationAdapter();

      const result = await adapter.send(makePayload({ recipient: 'user-1' }));

      expect(result.success).toBe(false);
