      await adapter.send(makePayload());

      expect(customTransport).toHaveBeenCalledTimes(1);
      expect(customTransport).toHaveBeenCalledWith(
        expect.objectContaining({
          to: '+15551234567',
          body: expect.any(String),
        }),
