    it('should handle non-Error exceptions', async () => {
      const failingTransport = vi.fn().mockRejectedValue('string error');
      adapter = new SmsNotificationAdapter({ transport: failingTransport });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown error');
    });

    it('should deliver multiple messages independently', async () => {
      await adapter.send(makePayload({ id: 'notif-0001', recipient: '+15551111111' }));
      await adapter.send(makePayload({ id: 'notif-0002', recipient: '+15552222222' }));

